command:example.dev:code:
PS Orch1:\> Get-OrchLicenseStats -Last "Month" | 
>> Group-Object robotType | 
>> ForEach-Object { 
>>     [PSCustomObject]@{
>>         RobotType = $_.Name
>>         TotalUsage = ($_.Group | Measure-Object count -Sum).Sum
>>         AverageDaily = [Math]::Round(($_.Group | Measure-Object count -Average).Average, 2)
>>     }
>> }

PS C:\> $drives = Get-OrchPSDrive
PS C:\> if ($drives.Count -eq 0) {
    Write-Host "No UiPath drives configured. Please run Edit-OrchConfig first"
} elseif ($drives.Count -eq 1) {
    Write-Host "Using drive: $($drives[0].Name)"
    cd "$($drives[0].Name):\"
} else {
    Write-Host "Multiple drives found:"
    $drives | Format-Table Name, Root, CurrentUser
    Write-Host "Which drive should I use for this operation?"
}

PS Orch1:\> $setting = Get-OrchUpdateSetting
PS Orch1:\> if ($setting.UpdateServerSource -eq "Orchestrator") {
>>     Write-Host "Using Orchestrator as update source"
>> } else {
>>     Write-Host "Using custom update source: $($setting.UpdateServerSource)"
>> }

PS Orch1Tm:\> $info = Get-TmServerInfo
PS Orch1Tm:\> if ($info.status -eq "OK") {
>>     Write-Host "Test Manager server is healthy"
>> } else {
>>     Write-Warning "Test Manager server status: $($info.status)"
>> }

PS C:\> $libraries = Get-ChildItem C:\Libraries\*.nupkg
PS C:\> foreach ($lib in $libraries) {
    try {
        $result = Import-OrchLibrary -Source $lib.FullName
        if ($result.Status -eq "OK") {
            Write-Host "Successfully imported: $($lib.Name)"
        } else {
            Write-Warning "Import failed for $($lib.Name): $($result.Status)"
        }
    } catch {
        Write-Warning "Error importing $($lib.Name): $($_.Exception.Message)"
    }
}
